function max_profit(prices) {
    let minP = prices[0], best = 0;
    for (let i=1;i<prices.length;i++) { best = Math.max(best, prices[i]-minP); minP = Math.min(minP, prices[i]); }
    return best;
}

function coin_change(coins, amount) {
    const INF = Infinity; const dp = new Array(amount+1).fill(INF); dp[0]=0;
    for (let i=1;i<=amount;i++) for (const c of coins) if (c<=i && dp[i-c]+1<dp[i]) dp[i]=dp[i-c]+1;
    const r = dp[amount]===INF ? -1 : dp[amount];
    return r===-1?r:r;
}

function count_bits(n) {
    const out = new Array(n+1).fill(0);
    for (let i=1;i<=n;i++) out[i] = out[i >> 1] + (i & 1);
    return out;
}

function euler_phi_sieve(n) {
    let result=n, x=n, p=2;
    while (p*p<=x) { if (x%p===0) { while (x%p===0) x=Math.floor(x/p); result-=Math.floor(result/p); } p++; }
    if (x>1) result-=Math.floor(result/x);
    return result;
}

function flood_fill(grid, sr, sc, new_color) {
    const m = grid.length, n = grid[0].length;
    const out = grid.map(r => r.slice());
    const old = out[sr][sc];
    if (old === new_color) return out;
    const stack = [[sr,sc]];
    out[sr][sc] = new_color;
    while (stack.length) {
        const [r,c] = stack.pop();
        for (const [dr,dc] of [[1,0],[-1,0],[0,1],[0,-1]]) {
            const nr=r+dr, nc=c+dc;
            if (nr>=0&&nr<m&&nc>=0&&nc<n&&out[nr][nc]===old) { out[nr][nc]=new_color; stack.push([nr,nc]); }
        }
    }
    return out;
}

function insert_interval(intervals, new_s, new_e) {
    const out = []; let i = 0; const n = intervals.length;
    while (i < n && intervals[i][1] < new_s) { out.push(intervals[i]); i++; }
    let s = new_s, e = new_e;
    while (i < n && intervals[i][0] <= e) { s = Math.min(s, intervals[i][0]); e = Math.max(e, intervals[i][1]); i++; }
    out.push([s,e]);
    while (i < n) { out.push(intervals[i]); i++; }
    return out;
}

function min_eating_speed(piles, h) {
    function hoursNeeded(speed) { let hrs=0; for (const p of piles) hrs+=Math.ceil(p/speed); return hrs; }
    let lo=1, hi=Math.max(...piles);
    while (lo<hi) { const mid=(lo+hi)>>1; if (hoursNeeded(mid)<=h) hi=mid; else lo=mid+1; }
    return lo;
}

function longest_common_substring(s1, s2) {
    const n=s1.length, m=s2.length;
    const dp=Array.from({length:n+1}, () => new Array(m+1).fill(0));
    let best=0;
    for (let i=1;i<=n;i++) for (let j=1;j<=m;j++) {
        if (s1[i-1]===s2[j-1]) { dp[i][j]=dp[i-1][j-1]+1; if (dp[i][j]>best) best=dp[i][j]; }
    }
    return best;
}

function longest_valid_parentheses(s) {
    const stack=[-1]; let best=0;
    for (let i=0;i<s.length;i++) {
        if (s[i]==='(') stack.push(i);
        else {
            stack.pop();
            if (stack.length===0) stack.push(i);
            else best=Math.max(best, i-stack[stack.length-1]);
        }
    }
    return best;
}

function longest_ones(nums, k) {
    let left=0, zeros=0, best=0;
    for (let right=0;right<nums.length;right++) {
        if (nums[right]===0) zeros++;
        while (zeros>k) { if (nums[left]===0) zeros--; left++; }
        best = Math.max(best, right-left+1);
    }
    return best;
}

function merge_two_lists(a, b) {
    const out=[]; let i=0,j=0;
    while (i<a.length && j<b.length) { if (a[i]<=b[j]) out.push(a[i++]); else out.push(b[j++]); }
    while (i<a.length) out.push(a[i++]);
    while (j<b.length) out.push(b[j++]);
    return out;
}

function missing_number(nums) {
    const n = nums.length; let expected = n*(n+1)/2; let actual = 0;
    for (const x of nums) actual += x;
    return (expected - actual);
}

function num_islands(grid) {
    const m = grid.length, n = grid[0].length;
    const visited = Array.from({length:m}, () => new Array(n).fill(false));
    let count = 0;
    function bfs(sr, sc) {
        const q = [[sr,sc]]; visited[sr][sc] = true; let qi = 0;
        while (qi < q.length) {
            const [r,c] = q[qi]; qi++;
            for (const [dr,dc] of [[1,0],[-1,0],[0,1],[0,-1]]) {
                const nr=r+dr, nc=c+dc;
                if (nr>=0&&nr<m&&nc>=0&&nc<n&&!visited[nr][nc]&&grid[nr][nc]===1) { visited[nr][nc]=true; q.push([nr,nc]); }
            }
        }
    }
    for (let i=0;i<m;i++) for (let j=0;j<n;j++) { if (grid[i][j]===1 && !visited[i][j]) { count++; bfs(i,j); } }
    return count;
}

function num_squares(n) {
    const dp=new Array(n+1).fill(Infinity); dp[0]=0;
    for (let i=1;i<=n;i++) for (let j=1;j*j<=i;j++) dp[i]=Math.min(dp[i], dp[i-j*j]+1);
    return dp[n];
}

function rod_cutting(prices, n) {
    const dp = new Array(n+1).fill(0);
    for (let i=1;i<=n;i++) for (let len=1;len<=Math.min(i,prices.length);len++) dp[i]=Math.max(dp[i], dp[i-len]+prices[len-1]);
    return dp[n];
}

function climb_stairs(n) {
    if (n===0) return 1;
    if (n<=2) return n;
    let a1=1, b=2;
    for (let i=3;i<=n;i++) { const t=a1+b; a1=b; b=t; }
    return b;
}

function least_interval(counts, cooldown) {
    const maxCount = Math.max(...counts);
    const maxCountFreq = counts.filter(c=>c===maxCount).length;
    const total = counts.reduce((a,b)=>a+b,0);
    const formula = (maxCount-1)*(cooldown+1)+maxCountFreq;
    return Math.max(total, formula);
}

function unbounded_knapsack(weights, values, capacity) {
    const dp=new Array(capacity+1).fill(0);
    for (let c=1;c<=capacity;c++) {
        for (let i=0;i<weights.length;i++) {
            if (weights[i]<=c) dp[c]=Math.max(dp[c], dp[c-weights[i]]+values[i]);
        }
    }
    return dp[capacity];
}
